// EVO-core Immune System — Auto-Reanimator v2.0
// Правила: BLOCK_07_immune_system.md
// Один Code node, без ветвлений, fallback Gemini→Ollama

const item = items[0].json;
const {
  taskDescription = '',
  baseInstructions = '',
  faultyOutput = '',
  errorLog = '',
  callbackUrl = '',
  sessionId = ''
} = item;

const prompt = `[EVO-CORE IMMUNE SYSTEM]
TASK: ${taskDescription.slice(0,400)}
BASE_INSTRUCTIONS: ${baseInstructions.slice(0,400)}
FAULTY_OUTPUT: ${faultyOutput.slice(0,400)}
ERROR_LOG: ${errorLog.slice(0,300)}

Find the EXACT point of failure.
Return a ZERO-FLUFF surgical code patch ONLY. No explanations.`;

// Получаем конфиг из переменных n8n
const geminiKey = $env.GEMINI_API_KEY || '';
const ollamaHost = $env.OLLAMA_HOST || 'http://localhost:11434';
const evoCallbackSecret = $env.EVO_API_SECRET || '';

// Цепочка попыток: Gemini x3 (backoff) → Ollama
const attempts = [
  {
    name: 'gemini-2.5-pro attempt 1',
    url: `https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-pro:generateContent?key=${geminiKey}`,
    body: { contents: [{ parts: [{ text: prompt }] }] },
    parse: (r) => r.candidates?.[0]?.content?.parts?.[0]?.text,
    delay: 0
  },
  {
    name: 'gemini-2.5-pro attempt 2',
    url: `https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-pro:generateContent?key=${geminiKey}`,
    body: { contents: [{ parts: [{ text: prompt }] }] },
    parse: (r) => r.candidates?.[0]?.content?.parts?.[0]?.text,
    delay: 5000
  },
  {
    name: 'gemini-2.0-flash fallback',
    url: `https://generativelanguage.googleapis.com/v1beta/models/gemini-2.0-flash:generateContent?key=${geminiKey}`,
    body: { contents: [{ parts: [{ text: prompt }] }] },
    parse: (r) => r.candidates?.[0]?.content?.parts?.[0]?.text,
    delay: 15000
  },
  {
    name: 'ollama local fallback',
    url: `${ollamaHost}/api/chat`,
    body: { model: 'llama3', messages: [{ role: 'user', content: prompt }], stream: false },
    parse: (r) => r.message?.content,
    delay: 45000
  }
];

let patch = null;
let usedProvider = null;
let lastError = null;

for (const attempt of attempts) {
  if (attempt.delay > 0) {
    await new Promise(r => setTimeout(r, attempt.delay));
  }
  try {
    const response = await this.helpers.request({
      method: 'POST',
      url: attempt.url,
      headers: { 'Content-Type': 'application/json' },
      body: attempt.body,
      json: true,
      timeout: 30000
    });
    const result = attempt.parse(response);
    if (result && result.trim().length > 10) {
      patch = result.trim();
      usedProvider = attempt.name;
      break;
    }
  } catch (e) {
    lastError = e.message;
    console.log(`[Immune] ${attempt.name} failed: ${e.message}`);
  }
}

if (!patch) {
  // Все попытки провалились — отправить уведомление Архитектору
  const failPayload = {
    status: 'reanimate_failed',
    sessionId,
    error: lastError,
    message: 'Все провайдеры недоступны. Требуется вмешательство Архитектора.'
  };
  if (callbackUrl) {
    await this.helpers.request({
      method: 'POST', url: callbackUrl,
      headers: { 'Content-Type': 'application/json', 'X-API-Key': evoCallbackSecret },
      body: failPayload, json: true
    });
  }
  return [{ json: { success: false, error: lastError } }];
}

// Отправить патч в callback
if (callbackUrl) {
  await this.helpers.request({
    method: 'POST',
    url: callbackUrl,
    headers: {
      'Content-Type': 'application/json',
      'X-API-Key': evoCallbackSecret
    },
    body: {
      status: 'reanimated',
      patch,
      sessionId,
      provider: usedProvider
    },
    json: true,
    timeout: 10000
  });
}

return [{
  json: {
    success: true,
    provider: usedProvider,
    patch_preview: patch.slice(0, 200) + '...'
  }
}];
